import{_ as s,o as e,c as n,ae as t}from"./chunks/framework.DTwQaIIa.js";const u=JSON.parse('{"title":"Enhancement Process","description":"","frontmatter":{},"headers":[],"relativePath":"en/modules/strengthen/process.md","filePath":"en/modules/strengthen/process.md"}'),p={name:"en/modules/strengthen/process.md"};function l(i,a,c,r,o,h){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="enhancement-process" tabindex="-1">Enhancement Process <a class="header-anchor" href="#enhancement-process" aria-label="Permalink to &quot;Enhancement Process&quot;">​</a></h1><p>This page provides a detailed description of EmakiStrengthen&#39;s complete enhancement process, success rate calculation, failure handling, data storage, and item refresh mechanism.</p><h2 id="complete-enhancement-process" tabindex="-1">Complete Enhancement Process <a class="header-anchor" href="#complete-enhancement-process" aria-label="Permalink to &quot;Complete Enhancement Process&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Open GUI</span></span>
<span class="line"><span>   └── Player executes /estrengthen open or opens the enhancement interface through other means</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Place Equipment</span></span>
<span class="line"><span>   └── Player places equipment into the target_item slot (slot 13)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Recipe Resolution (Recipe Resolve)</span></span>
<span class="line"><span>   ├── StrengthenRecipeResolver iterates through all loaded recipes</span></span>
<span class="line"><span>   ├── Matches against match rules one by one (source_types → source_ids → source_patterns → slot_groups → lore_contains → stats_any)</span></span>
<span class="line"><span>   ├── Match found → Load the corresponding recipe, display current star level and next stage info</span></span>
<span class="line"><span>   └── No match → Prompt that the equipment cannot be enhanced</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Place Materials</span></span>
<span class="line"><span>   └── Player places materials into material_input slots (slots 19/20/29/30)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. Material Plan Resolution (Material Plan Resolve)</span></span>
<span class="line"><span>   ├── MaterialPlanResolver reads the materials requirements for the current star stage</span></span>
<span class="line"><span>   ├── Checks material slots one by one to see if items match</span></span>
<span class="line"><span>   ├── Match found → Mark materials as consumable, update preview</span></span>
<span class="line"><span>   └── Match failed → Prompt for missing materials</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. Preview Calculation</span></span>
<span class="line"><span>   ├── Calculate stat changes after enhancement</span></span>
<span class="line"><span>   ├── Calculate success rate (including temper bonus)</span></span>
<span class="line"><span>   ├── Calculate economy cost</span></span>
<span class="line"><span>   └── Display preview in the preview_display slot (slot 15)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. Confirm Enhancement</span></span>
<span class="line"><span>   └── Player clicks the confirm button (slot 40)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>8. Execute Enhancement Attempt</span></span>
<span class="line"><span>   ├── ChanceCalculator computes the final success rate</span></span>
<span class="line"><span>   ├── Random roll for success/failure</span></span>
<span class="line"><span>   ├── Success → Enter success flow</span></span>
<span class="line"><span>   └── Failure → Enter failure flow</span></span>
<span class="line"><span></span></span>
<span class="line"><span>9. Success Flow</span></span>
<span class="line"><span>   ├── Increase star level</span></span>
<span class="line"><span>   ├── StrengthenSnapshotBuilder rebuilds the enhancement layer</span></span>
<span class="line"><span>   ├── Write new stats and attributes</span></span>
<span class="line"><span>   ├── Update structured_presentation</span></span>
<span class="line"><span>   ├── Execute success_actions</span></span>
<span class="line"><span>   └── Reset temper level to 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>10. Failure Flow</span></span>
<span class="line"><span>    ├── Check for protection items</span></span>
<span class="line"><span>    ├── Protected → Consume protection item, no star loss</span></span>
<span class="line"><span>    ├── Unprotected → Reduce star or generate crack based on configuration</span></span>
<span class="line"><span>    ├── Temper level +1 (up to max_temper)</span></span>
<span class="line"><span>    └── Execute failure_actions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>11. PDC Write</span></span>
<span class="line"><span>    ├── StrengthenPdcAttributeWriter updates PDC data</span></span>
<span class="line"><span>    ├── Write current star level, temper level, crack level, etc.</span></span>
<span class="line"><span>    └── Update audit data</span></span>
<span class="line"><span></span></span>
<span class="line"><span>12. Economy Deduction</span></span>
<span class="line"><span>    └── StrengthenEconomyService deducts fees based on cost_formula</span></span>
<span class="line"><span></span></span>
<span class="line"><span>13. Consume Materials</span></span>
<span class="line"><span>    └── Deduct the corresponding amount of materials from material slots</span></span>
<span class="line"><span></span></span>
<span class="line"><span>14. Broadcast</span></span>
<span class="line"><span>    ├── Star level ≥ local_stars → Local broadcast (visible to players within radius)</span></span>
<span class="line"><span>    └── Star level ≥ global_stars → Global broadcast (visible server-wide)</span></span></code></pre></div><h2 id="chancecalculator-success-rate-calculation" tabindex="-1">ChanceCalculator Success Rate Calculation <a class="header-anchor" href="#chancecalculator-success-rate-calculation" aria-label="Permalink to &quot;ChanceCalculator Success Rate Calculation&quot;">​</a></h2><h3 id="base-formula" tabindex="-1">Base Formula <a class="header-anchor" href="#base-formula" aria-label="Permalink to &quot;Base Formula&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Final Success Rate = min(base_rate + temper_bonus, success_chance_cap)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Source</th></tr></thead><tbody><tr><td><code>base_rate</code></td><td>Base success rate</td><td>Recipe <code>success_rates</code> or global <code>config.yml</code></td></tr><tr><td><code>temper_bonus</code></td><td>Temper bonus</td><td><code>temper × temper_chance_bonus_per_level</code></td></tr><tr><td><code>success_chance_cap</code></td><td>Success rate cap</td><td>Recipe <code>limits.success_chance_cap</code></td></tr></tbody></table><h3 id="calculation-example" tabindex="-1">Calculation Example <a class="header-anchor" href="#calculation-example" aria-label="Permalink to &quot;Calculation Example&quot;">​</a></h3><p>Assume:</p><ul><li>Base success rate for target star 7 = 40%</li><li>Current temper level = 5</li><li>Temper bonus per level = 1.5%</li><li>Success rate cap = 95%</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>temper_bonus = 5 × 1.5 = 7.5%</span></span>
<span class="line"><span>Final Success Rate = min(40 + 7.5, 95) = 47.5%</span></span></code></pre></div><h3 id="temper-mechanism" tabindex="-1">Temper Mechanism <a class="header-anchor" href="#temper-mechanism" aria-label="Permalink to &quot;Temper Mechanism&quot;">​</a></h3><p>Temper is a compensation mechanism that accumulates on failure:</p><ul><li>Each enhancement failure increases temper level by 1 (up to <code>max_temper</code>)</li><li>Each temper level provides <code>temper_chance_bonus_per_level</code> success rate bonus</li><li>Temper level resets to 0 after a successful enhancement</li><li>Temper level is stored in the equipment&#39;s PDC data</li></ul><h2 id="failure-handling" tabindex="-1">Failure Handling <a class="header-anchor" href="#failure-handling" aria-label="Permalink to &quot;Failure Handling&quot;">​</a></h2><h3 id="with-protection-item" tabindex="-1">With Protection Item <a class="header-anchor" href="#with-protection-item" aria-label="Permalink to &quot;With Protection Item&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Enhancement failed</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Protection item detected</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Consume protection item</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Star level unchanged, no crack generated</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Temper level +1</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Execute failure_actions</span></span></code></pre></div><h3 id="without-protection-item" tabindex="-1">Without Protection Item <a class="header-anchor" href="#without-protection-item" aria-label="Permalink to &quot;Without Protection Item&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Enhancement failed</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>No protection item</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Execute penalty based on configuration:</span></span>
<span class="line"><span>    ├── Star loss (star level -1, minimum 0)</span></span>
<span class="line"><span>    └── Generate crack (crack_level +1)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Temper level +1</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Execute failure_actions</span></span></code></pre></div><p>Crack is a damage state on equipment that may affect the equipment&#39;s stats or appearance. Admins can clear it using the <code>/estrengthen clearcrack</code> command.</p><h2 id="data-storage" tabindex="-1">Data Storage <a class="header-anchor" href="#data-storage" aria-label="Permalink to &quot;Data Storage&quot;">​</a></h2><p>Enhancement data is stored on the equipment item via PDC (PersistentDataContainer). Data travels with the item and does not depend on external databases. See the <a href="./api.html">API &amp; Integration</a> page for detailed data structures and access methods.</p><h2 id="strengthenrefreshservice" tabindex="-1">StrengthenRefreshService <a class="header-anchor" href="#strengthenrefreshservice" aria-label="Permalink to &quot;StrengthenRefreshService&quot;">​</a></h2><p>The item refresh service is responsible for automatically refreshing the display state of equipment when the enhancement layer data signature changes.</p><h3 id="trigger-timing" tabindex="-1">Trigger Timing <a class="header-anchor" href="#trigger-timing" aria-label="Permalink to &quot;Trigger Timing&quot;">​</a></h3><ul><li>When a player opens their inventory</li><li>When a player switches held items</li><li>When an admin executes <code>/estrengthen refresh</code></li><li>After recipe resources are reloaded</li></ul><h3 id="refresh-flow" tabindex="-1">Refresh Flow <a class="header-anchor" href="#refresh-flow" aria-label="Permalink to &quot;Refresh Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Check if the item contains strengthen layer data</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Read the strengthen audit map from item PDC</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Get recipe_id, look up the corresponding recipe</span></span>
<span class="line"><span>    ├── Recipe not found → Skip refresh</span></span>
<span class="line"><span>    └── Recipe found ↓</span></span>
<span class="line"><span>Calculate the signature of the current recipe definition</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Compare with the materials_signature stored on the item</span></span>
<span class="line"><span>    ├── Signatures match → Skip refresh</span></span>
<span class="line"><span>    └── Signatures differ → Execute refresh</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>    Get the structured_presentation for the corresponding star stage based on current_star</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>    Rebuild item display via AssemblyService</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>    Update materials_signature</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>The refresh service only updates the item&#39;s display layer (name, Lore) and does not change already-written stat values. To reset stats, use the <code>/estrengthen setstar</code> command to re-set the star level.</p></div>`,30)])])}const m=s(p,[["render",l]]);export{u as __pageData,m as default};
